const row = $input.item.json;

// Se a query nao retornou dados reais, encerra silenciosamente
if (!row || !row.nome_requerente) {
  return null;
}

const cpf = row.cpf;
const pt_id = row.pt_id;
const consulta_id = row.consulta_id;
const whatsapp_from = row.whatsapp_from;
const nome_requerente = row.nome_requerente;
const email = row.email || 'não informado';

// Parse do campo processos: pode ser objeto (postgres jsonb) ou string (text)
let lista_processos = [];
try {
  let processosObj;
  if (typeof row.processos === 'string') {
    processosObj = JSON.parse(row.processos);
  } else {
    processosObj = row.processos;
  }
  lista_processos = (processosObj.lista || []).map(p => p.numero);
} catch(e) {
  lista_processos = ['Não foi possível extrair os números dos processos'];
}

const processos_formatados_texto = lista_processos.join('\n');
const processos_formatados_html = lista_processos.map(n => `<li>${n}</li>`).join('');

const msg_cliente = `Prezado Sr(a) ${nome_requerente} recebemos a sua solicitação e informamos que, devido a uma instabilidade do sistema do Tribunal de Justiça do Estado de São Paulo, o seu laudo diagnóstico de precatório será enviado em até 7 (sete) dias úteis.\n\nContamos com a sua compreensão e agradecemos o contato.\n\nAtenciosamente,\nRevisa Precatório`;

const msg_interna_texto = `CPF ${cpf} do cliente ${nome_requerente} possui laudo parcial e requer processamento manual, numero dos processos envolvidos:\n${processos_formatados_texto}\n\ne enviar ao email ${email}`;

const msg_interna_html = `<p>CPF <strong>${cpf}</strong> do cliente <strong>${nome_requerente}</strong> possui laudo parcial e requer processamento manual.</p><p><strong>Número dos processos envolvidos:</strong></p><ul>${processos_formatados_html}</ul><p>Enviar ao email: <a href="mailto:${email}">${email}</a></p>`;

return {
  json: {
    cpf,
    pt_id,
    consulta_id,
    whatsapp_from,
    nome_requerente,
    email,
    msg_cliente,
    msg_interna_texto,
    msg_interna_html
  }
};
